    // Register with the built-in sample dataset system
    // Expose globally for the sample loader to pick up
    window.SYNPUF_DATASETS = SYNPUF_DATASETS;

    // Add SynPUF option to any existing sample dataset UI
    // Also listen for the custom event from the sample loader button
    function loadSynPUF(idx) {
      var ds = SYNPUF_DATASETS[idx];
      if (!ds) return;
      var event = new CustomEvent('dataglow:load-sample', {
        detail: {
          name: ds.name,
          columns: ds.columns,
          rows: ds.rows,
          label: ds.label,
          description: ds.description
        }
      });
      document.dispatchEvent(event);
      if (typeof showToast === 'function') {
        showToast('Loaded: ' + ds.label + ' (' + ds.rows.length + ' rows)', 'success');
      }
    }
    window.loadSynPUF = loadSynPUF;

    // Build the SynPUF section in the sample panel if it exists
    document.addEventListener('DOMContentLoaded', function () {
      var samplePanel = document.getElementById('sample-panel') || document.getElementById('sample-datasets-panel');
      if (samplePanel) {
        var section = document.createElement('div');
        section.innerHTML = '<div style="font-size:11px;font-weight:600;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.05em;margin:12px 0 6px;">SynPUF (Synthetic Medicare)</div>';
        SYNPUF_DATASETS.forEach(function(ds, i) {
          var btn = document.createElement('button');
          btn.className = 'sample-dataset-btn';
          btn.style.cssText = 'display:block;width:100%;text-align:left;padding:8px 10px;margin-bottom:4px;background:var(--surface-alt);border:1px solid var(--border);border-radius:6px;color:var(--text);font-size:12px;cursor:pointer;';
          btn.innerHTML = '<strong>' + ds.label + '</strong><br><span style="color:var(--text-muted);font-size:11px;">' + ds.description.substring(0,80) + '...</span>';
          btn.addEventListener('click', function() { loadSynPUF(i); });
          section.appendChild(btn);
        });
        samplePanel.appendChild(section);
      }
    });

    // Listen for sample load event
    document.addEventListener('dataglow:load-sample', function(e) {
      var detail = e.detail;
      if (!detail || !detail.columns || !detail.rows) return;
      // Dispatch dataset-loaded if handler exists
      if (window.handleIncomingDataset) {
        window.handleIncomingDataset(detail.name, detail.columns, detail.rows);
      }
    });
